# pip install simple-salesforce anthropic
from simple_salesforce import Salesforce
from anthropic import Anthropic
import os, json

sf = Salesforce(
    username=os.environ["SF_USERNAME"],
    password=os.environ["SF_PASSWORD"],
    security_token=os.environ["SF_TOKEN"],
)
client = Anthropic()

TOOLS = [
    {
        "name": "search_contacts",
        "description": "Search Salesforce contacts by name or email.",
        "input_schema": {
            "type": "object",
            "properties": {"query": {"type": "string", "description": "Name or email to search"}},
            "required": ["query"],
        },
    },
    {
        "name": "get_open_opportunities",
        "description": "Return open sales opportunities for an account.",
        "input_schema": {
            "type": "object",
            "properties": {"account_name": {"type": "string"}},
            "required": ["account_name"],
        },
    },
    {
        "name": "create_note",
        "description": "Add a note to a Salesforce contact.",
        "input_schema": {
            "type": "object",
            "properties": {
                "contact_id": {"type": "string"},
                "note": {"type": "string"},
            },
            "required": ["contact_id", "note"],
        },
    },
]

def execute_tool(name: str, inputs: dict) -> str:
    if name == "search_contacts":
        q = inputs["query"].replace("'", "\\'")
        results = sf.query(
            f"SELECT Id, Name, Email, Phone, AccountId FROM Contact "
            f"WHERE Name LIKE '%{q}%' OR Email LIKE '%{q}%' LIMIT 5"
        )
        return json.dumps(results["records"])

    if name == "get_open_opportunities":
        acct = inputs["account_name"].replace("'", "\\'")
        results = sf.query(
            f"SELECT Name, StageName, Amount, CloseDate FROM Opportunity "
            f"WHERE Account.Name LIKE '%{acct}%' AND IsClosed = false LIMIT 10"
        )
        return json.dumps(results["records"])

    if name == "create_note":
        # Require human approval before writing — see approval pattern below
        note = sf.Note.create({
            "ParentId": inputs["contact_id"],
            "Body": inputs["note"],
        })
        return json.dumps({"id": note["id"], "success": note["success"]})

    return "Unknown tool"

def crm_agent(user_query: str) -> str:
    messages = [{"role": "user", "content": user_query}]
    while True:
        response = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=600,
            tools=TOOLS,
            system="You are a CRM assistant. Use tools to answer questions about contacts and opportunities.",
            messages=messages,
        )
        if response.stop_reason == "end_turn":
            return next((b.text for b in response.content if b.type == "text"), "")
        if response.stop_reason == "tool_use":
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    result = execute_tool(block.name, block.input)
                    tool_results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
            messages.append({"role": "assistant", "content": response.content})
            messages.append({"role": "user", "content": tool_results})
        else:
            break
    return ""

