# pip install hubspot-api-client anthropic
from hubspot import HubSpot
from hubspot.crm.contacts import PublicObjectSearchRequest
from anthropic import Anthropic
import os, json

hs = HubSpot(access_token=os.environ["HUBSPOT_ACCESS_TOKEN"])
client = Anthropic()

def search_hubspot_contacts(query: str) -> list[dict]:
    search = PublicObjectSearchRequest(
        query=query,
        limit=5,
        properties=["firstname", "lastname", "email", "phone", "company"],
    )
    results = hs.crm.contacts.search_api.do_search(public_object_search_request=search)
    return [
        {
            "id": r.id,
            "name": f"{r.properties.get('firstname','')} {r.properties.get('lastname','')}".strip(),
            "email": r.properties.get("email"),
            "company": r.properties.get("company"),
            "phone": r.properties.get("phone"),
        }
        for r in results.results
    ]

def get_contact_deals(contact_id: str) -> list[dict]:
    associations = hs.crm.contacts.associations_api.get_all(
        contact_id=contact_id, to_object_type="deals"
    )
    deal_ids = [a.id for a in associations.results]
    deals = []
    for deal_id in deal_ids[:5]:
        deal = hs.crm.deals.basic_api.get_by_id(
            deal_id, properties=["dealname", "dealstage", "amount", "closedate"]
        )
        deals.append(deal.properties)
    return deals

def create_hubspot_note(contact_id: str, note_body: str) -> dict:
    note = hs.crm.objects.notes.basic_api.create(
        simple_public_object_input={
            "properties": {
                "hs_note_body": note_body,
                "hs_timestamp": str(int(__import__("time").time() * 1000)),
            }
        }
    )
    # Associate the note with the contact
    hs.crm.objects.notes.associations_api.create(
        note_id=note.id,
        to_object_type="contacts",
        to_object_id=contact_id,
        association_type="note_to_contact",
    )
    return {"note_id": note.id, "contact_id": contact_id}

# Generic ERP REST API pattern (works with NetSuite, Odoo, or similar)
import httpx, os
from anthropic import Anthropic

client = Anthropic()
ERP_BASE = os.environ.get("ERP_BASE_URL", "https://erp.example.com/api/v1")
ERP_TOKEN = os.environ.get("ERP_TOKEN", "")

def erp_get(path: str, params: dict | None = None) -> dict:
    with httpx.Client(base_url=ERP_BASE, headers={"Authorization": f"Bearer {ERP_TOKEN}"}) as c:
        resp = c.get(path, params=params or {}, timeout=15)
        resp.raise_for_status()
        return resp.json()

def get_order_status(order_id: str) -> dict:
    return erp_get(f"/orders/{order_id}")

def get_inventory_level(sku: str) -> dict:
    return erp_get("/inventory", params={"sku": sku})

def get_customer_invoices(customer_id: str, status: str = "open") -> list[dict]:
    data = erp_get("/invoices", params={"customer_id": customer_id, "status": status})
    return data.get("results", [])

